const fs = require('fs');

let content = fs.readFileSync('/Users/animeshpathak/ocfaqproj/faq-website/frontend/src/components/UserManagementTab.jsx', 'utf-8');

const replacement = `// ─── Status badge ─────────────────────────────────────────────────────────────
function StatusBadge({ isSuspended, isBanned }) {
  if (isBanned)    return <span className="px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-100 text-red-700 dark:bg-red-500/20 dark:text-red-400">Banned</span>;
  if (isSuspended) return <span className="px-2.5 py-0.5 rounded-full text-xs font-medium bg-orange-100 text-orange-700 dark:bg-orange-500/20 dark:text-orange-400">Suspended</span>;
  return <span className="px-2.5 py-0.5 rounded-full text-xs font-medium bg-emerald-100 text-emerald-700 dark:bg-emerald-500/20 dark:text-emerald-400">Active</span>;
}

// ─── Drawer ───────────────────────────────────────────────────────────────────
function Drawer({ isOpen, onClose, user, onUserUpdate }) {
  const drawerRef = useRef(null);

  const [formData, setFormData] = useState({});
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (user) {
      setFormData({
        fullName: user.fullName || '',
        username: user.username || '',
        email: user.email || '',
        role: user.role || 'user',
        institution: user.institution || ''
      });
    }
  }, [user]);

  const hasChanges = user && (
    formData.fullName !== (user.fullName || '') ||
    formData.username !== (user.username || '') ||
    formData.email !== (user.email || '') ||
    formData.role !== (user.role || 'user') ||
    formData.institution !== (user.institution || '')
  );

  // Close on ESC
  useEffect(() => {
    const handler = (e) => { if (e.key === 'Escape') onClose(); };
    if (isOpen) document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [isOpen, onClose]);

  // Close on click outside
  const handleBackdrop = (e) => {
    if (drawerRef.current && !drawerRef.current.contains(e.target)) onClose();
  };

  // Lock body scroll while drawer open
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      // Hide Bee when drawer is open
      document.documentElement.style.setProperty('--bee-visibility', 'none');
    } else {
      document.body.style.overflow = '';
      document.documentElement.style.setProperty('--bee-visibility', 'block');
    }
    return () => { 
      document.body.style.overflow = ''; 
      document.documentElement.style.setProperty('--bee-visibility', 'block');
    };
  }, [isOpen]);

  if (!isOpen) return null;

  const formatDate = (d) => {
    if (!d) return '—';
    return new Date(d).toLocaleDateString('en-GB', { day: '2-digit', month: 'long', year: 'numeric' });
  };

  const handleSaveProfile = async () => {
    setSaving(true);
    try {
      const res = await axiosClient.put(\`/user-management/users/\${user._id}\`, formData);
      toast.success('User updated successfully');
      onUserUpdate(res.data.user);
    } catch (err) {
      toast.error(err.response?.data?.error || 'Failed to update user');
    } finally {
      setSaving(false);
    }
  };

  const isDemoUser = process.env.NODE_ENV === 'development' && (user?.email?.endsWith('@infracon.com') || user?.email?.endsWith('@test.com'));

  return (
    <div
      className="fixed inset-0 z-50 flex justify-end"
      onClick={handleBackdrop}
      aria-modal="true"
      role="dialog"
    >
      <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity" />

      <div
        ref={drawerRef}
        className="relative w-full sm:w-[500px] md:w-[600px] lg:w-[650px] h-full bg-white dark:bg-slate-900 border-l border-slate-200 dark:border-slate-800 flex flex-col shadow-2xl overflow-hidden transition-transform"
      >
        <div className="flex items-center justify-between px-6 py-5 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50 shrink-0">
          <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">Edit User Profile</h2>
          <button
            onClick={onClose}
            className="p-2 rounded-lg text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 transition cursor-pointer"
          >
            <X size={20} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto pb-24">

          {/* Section 1: User Header */}
          <div className="p-6 pb-2 border-b border-slate-100 dark:border-slate-800/50">
            <div className="flex items-start gap-5">
              <div className="w-20 h-20 rounded-2xl bg-indigo-50 dark:bg-indigo-500/10 border border-indigo-100 dark:border-indigo-500/20 flex items-center justify-center shrink-0 shadow-sm">
                <span className="text-2xl font-bold text-indigo-600 dark:text-indigo-400">
                  {user?.fullName
                    ? user.fullName.split(' ').map((n) => n[0]).join('').toUpperCase().slice(0, 2)
                    : <UserIcon size={32} className="text-indigo-400" />}
                </span>
              </div>
              <div className="flex-1 min-w-0 pt-1">
                <div className="flex items-center gap-3">
                  <h3 className="text-2xl font-bold text-slate-900 dark:text-white truncate">{user?.fullName || '—'}</h3>
                  <StatusBadge isSuspended={user?.isSuspended} isBanned={user?.isBanned} />
                  {isDemoUser && <span className="px-2 py-0.5 rounded text-xs font-bold bg-amber-100 text-amber-800 dark:bg-amber-500/20 dark:text-amber-400 uppercase tracking-wide">Demo Data</span>}
                </div>
                <p className="text-slate-500 dark:text-slate-400 font-medium mt-1">@{user?.username || '—'}</p>
                <div className="flex items-center gap-4 mt-3 text-sm text-slate-500 dark:text-slate-400">
                  <span className="flex items-center gap-1.5"><Clock size={14} /> Joined {formatDate(user?.createdAt)}</span>
                </div>
              </div>
            </div>
          </div>

          {/* Section 2: Account Information */}
          <div className="p-6">
            <SectionHeading>Account Information</SectionHeading>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5 mt-4">
              <div className="space-y-1.5">
                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300">Email Address</label>
                <input 
                  type="email" 
                  value={formData.email || ''} 
                  onChange={e => setFormData({...formData, email: e.target.value})}
                  className="w-full bg-white dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 rounded-lg px-3 py-2 text-sm text-slate-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                />
              </div>
              <div className="space-y-1.5">
                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300">Username</label>
                <input 
                  type="text" 
                  value={formData.username || ''} 
                  onChange={e => setFormData({...formData, username: e.target.value})}
                  className="w-full bg-white dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 rounded-lg px-3 py-2 text-sm text-slate-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                />
              </div>
              <div className="space-y-1.5">
                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300">Full Name</label>
                <input 
                  type="text" 
                  value={formData.fullName || ''} 
                  onChange={e => setFormData({...formData, fullName: e.target.value})}
                  className="w-full bg-white dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 rounded-lg px-3 py-2 text-sm text-slate-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                />
              </div>
              <div className="space-y-1.5">
                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300">Role</label>
                <select 
                  value={formData.role || 'user'} 
                  onChange={e => setFormData({...formData, role: e.target.value})}
                  className="w-full bg-white dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 rounded-lg px-3 py-2 text-sm text-slate-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-indigo-500 capitalize"
                >
                  <option value="user">User</option>
                  <option value="mentor">Mentor</option>
                  <option value="moderator">Moderator</option>
                  <option value="admin">Admin</option>
                </select>
              </div>
              <div className="space-y-1.5 md:col-span-2">
                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300">Institution / Organization</label>
                <input 
                  type="text" 
                  value={formData.institution || ''} 
                  onChange={e => setFormData({...formData, institution: e.target.value})}
                  className="w-full bg-white dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 rounded-lg px-3 py-2 text-sm text-slate-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                />
              </div>
            </div>
          </div>

          {/* Section 3: Statistics */}
          <div className="px-6 pb-6">
            <SectionHeading>Statistics</SectionHeading>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-4">
              <StatCard label="Spurti Points" value={user?.spurtiPoints ?? 0} accent="indigo" />
              <StatCard label="Pizza Slices" value={user?.pizzaSlices ?? 0} accent="amber" />
              <StatCard label="Contributions" value={user?.contributionsCount ?? 0} accent="emerald" />
              <StatCard label="Answers" value={user?.answersCount ?? 0} accent="blue" />
            </div>
          </div>

          <div className="px-6 pb-6 space-y-8">
            <StatusSection user={user} onUpdate={onUserUpdate} />
            <RewardsSection user={user} onUpdate={onUserUpdate} />
            <ActivitySection userId={user?._id} onRefresh={onUserUpdate} />
            <ModerationSection userId={user?._id} onRefresh={onUserUpdate} />
          </div>
        </div>

        {/* Section 6: Save Actions Sticky Footer */}
        <div className="absolute bottom-0 left-0 right-0 p-4 border-t border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 z-10 flex items-center justify-end gap-3 shadow-[0_-10px_20px_rgba(0,0,0,0.05)] dark:shadow-[0_-10px_20px_rgba(0,0,0,0.2)]">
          <button 
            onClick={onClose}
            className="px-4 py-2 rounded-lg font-medium text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 transition"
          >
            Cancel
          </button>
          <button 
            onClick={handleSaveProfile}
            disabled={!hasChanges || saving}
            className="px-5 py-2 rounded-lg font-medium bg-indigo-600 text-white hover:bg-indigo-700 transition disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
          >
            {saving ? <RefreshCw size={16} className="animate-spin" /> : null}
            Save Changes
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Helper components ────────────────────────────────────────────────────────
function SectionHeading({ children }) {
  return (
    <h3 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">
      {children}
    </h3>
  );
}

function ProfileRow({ label, value }) {
  return (
    <div className="flex justify-between items-center py-2 border-b border-slate-100 dark:border-slate-800/50 last:border-0">
      <span className="text-sm text-slate-500 dark:text-slate-400">{label}</span>
      <span className="text-sm text-slate-900 dark:text-slate-100 font-medium">{value}</span>
    </div>
  );
}

function StatCard({ label, value, accent = 'indigo' }) {
  const styles = {
    indigo:  'bg-indigo-50 dark:bg-indigo-500/10 border-indigo-100 dark:border-indigo-500/20 text-indigo-700 dark:text-indigo-300',
    amber:   'bg-amber-50 dark:bg-amber-500/10 border-amber-100 dark:border-amber-500/20 text-amber-700 dark:text-amber-300',
    emerald: 'bg-emerald-50 dark:bg-emerald-500/10 border-emerald-100 dark:border-emerald-500/20 text-emerald-700 dark:text-emerald-300',
    blue:    'bg-blue-50 dark:bg-blue-500/10 border-blue-100 dark:border-blue-500/20 text-blue-700 dark:text-blue-300',
  }[accent] || 'bg-slate-50 border-slate-100 text-slate-700';

  return (
    <div className={\`\${styles} rounded-xl border p-4 flex flex-col justify-center shadow-sm\`}>
      <span className="text-2xl font-bold mb-1 leading-none">{Number(value).toLocaleString()}</span>
      <span className="text-xs font-medium uppercase tracking-wide opacity-80">{label}</span>
    </div>
  );
}`;

content = content.replace(/\/\/ ─── Status badge[\s\S]*?(?=\/\/ ─── Relative time)/, replacement + '\n');
fs.writeFileSync('/Users/animeshpathak/ocfaqproj/faq-website/frontend/src/components/UserManagementTab.jsx', content);
console.log("Drawer rewritten");

import React, { useState } from 'react';
import axiosClient from '../api/axiosClient';
import toast from 'react-hot-toast';
import { ArrowRight, RefreshCcw } from 'lucide-react';
import { useBannedClass } from '../hooks/useBannedTheme';

export default function AppealCard({ ticketId, currentStatus, onStatusChange }) {
  const [isAppealing, setIsAppealing] = useState(false);
  const { borderAmber, borderAmberLight, bgAmber, bgAmberDark, textAmber, textAmberDark } = useBannedClass();

  const canAppeal = currentStatus === 'resolved' || currentStatus === 'rejected';

  const handleAppeal = async () => {
    if (!canAppeal) return;
    setIsAppealing(true);
    try {
      const res = await axiosClient.post(`/personal-issues/${ticketId}/appeal`);
      toast.success(res.data.message || 'Ticket appealed successfully.');
      if (onStatusChange) onStatusChange('under_review');
    } catch (err) {
      toast.error(err.response?.data?.error || 'Failed to appeal ticket.');
    } finally {
      setIsAppealing(false);
    }
  };

  const cardClass = [
    'glass-card rounded-3xl p-6 md:p-8',
    'flex flex-col md:flex-row items-start md:items-center justify-between gap-5',
    'backdrop-blur-xl shadow-sm mt-8',
    borderAmber,
    bgAmber,
  ].join(' ');

  const iconClass = [
    'p-2 rounded-xl h-fit shrink-0 border shadow-sm',
    bgAmberDark,
    textAmber,
    borderAmberLight,
  ].join(' ');

  return (
    <div className={cardClass}>
      <div className="flex gap-4">
        <div className={iconClass}>
          <RefreshCcw size={18} strokeWidth={2.5} />
        </div>
        <div>
          <h3 className="font-bold font-bricolage text-slate-800 dark:text-slate-200 text-base md:text-lg">Query Appeal / Re-escalation</h3>
          <p className="text-slate-600 dark:text-slate-400 text-sm mt-1 leading-relaxed">Not satisfied with the resolution? Appeal to a higher authority.</p>
        </div>
      </div>

      <button
        onClick={handleAppeal}
        disabled={!canAppeal || isAppealing}
        className={`flex items-center justify-center gap-2 px-6 py-2.5 rounded-xl text-sm font-semibold font-bricolage transition-all duration-300 border w-full md:w-auto shrink-0 shadow-sm
          ${canAppeal
            ? 'border-emerald-300/50 dark:border-emerald-700/50 text-emerald-700 dark:text-emerald-300 bg-emerald-50 dark:bg-emerald-900/20 hover:bg-emerald-100 dark:hover:bg-emerald-800/40 hover:border-emerald-400 dark:hover:border-emerald-500/50 hover:shadow-[0_0_20px_rgba(16,185,129,0.2)] cursor-pointer'
            : 'border-slate-200 dark:border-white/5 text-slate-400 dark:text-slate-500 bg-slate-50 dark:bg-black/20 cursor-not-allowed opacity-70'}`}
      >
        {isAppealing ? 'Appealing...' : 'Appeal'}
        <ArrowRight size={16} strokeWidth={2.5} className={isAppealing ? 'animate-spin' : ''} />
      </button>
    </div>
  );
}

import { useState } from 'react';
import {
  FileText, Image, Video, Music, Download, Eye, X, ExternalLink,
  ZoomIn, Play, Pause
} from 'lucide-react';
import axiosClient from '../api/axiosClient';

function formatSize(bytes) {
  if (!bytes) return '0 B';
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

function formatDuration(seconds) {
  if (!seconds) return null;
  const m = Math.floor(seconds / 60);
  const s = Math.round(seconds % 60);
  return m > 0 ? `${m}m ${s}s` : `${s}s`;
}

function FileIcon({ type, size = 18 }) {
  if (type?.startsWith('image/'))  return <Image    size={size} className="text-cyan-400" />;
  if (type?.startsWith('video/'))  return <Video    size={size} className="text-violet-400" />;
  if (type?.startsWith('audio/'))  return <Music    size={size} className="text-emerald-400" />;
  if (type?.includes('pdf'))       return <FileText size={size} className="text-red-400" />;
  if (type?.includes('word'))      return <FileText size={size} className="text-blue-400" />;
  return <FileText size={size} className="text-slate-400" />;
}

function isImage(type) { return type?.startsWith('image/'); }
function isVideo(type) { return type?.startsWith('video/'); }
function isAudio(type) { return type?.startsWith('audio/'); }
function isPDF(type)   { return type?.includes('pdf'); }
function isDocX(type)  { return type?.includes('word'); }

function getFileUrl(relativeUrl) {
  if (!relativeUrl) return '';
  if (relativeUrl.startsWith('http')) return relativeUrl;
  const base = axiosClient.defaults.baseURL?.replace(/\/$/, '') || '';
  return `${base}${relativeUrl}`;
}

// ── Single attachment row ──────────────────────────────────────────────────────
function AttachmentItem({ att, compact = false, onRemove, showUploader = false }) {
  const [playing, setPlaying] = useState(false);
  const fileUrl = getFileUrl(att.fileUrl);
  const type = att.fileType;

  return (
    <div className={`flex items-center gap-3 px-4 py-3 rounded-xl bg-white/[0.03] border border-white/[0.06] ${compact ? 'py-2 px-3' : ''}`}>
      {/* Icon */}
      <div className="flex-shrink-0 w-9 h-9 rounded-lg bg-white/[0.04] flex items-center justify-center">
        <FileIcon type={type} size={16} />
      </div>

      {/* Info */}
      <div className="flex-1 min-w-0">
        <p className="text-xs font-semibold text-slate-300 font-bricolage truncate leading-snug">
          {att.fileName}
        </p>
        <div className="flex items-center gap-2 flex-wrap mt-0.5">
          <span className="text-[10px] text-slate-600 font-bricolage">{formatSize(att.fileSize)}</span>
          {att.duration && (
            <span className="text-[10px] text-slate-700 font-bricolage">{formatDuration(att.duration)}</span>
          )}
          {!compact && showUploader && att.uploadedBy && (
            <span className="text-[10px] text-amber-500/50 font-bricolage">
              by {typeof att.uploadedBy === 'object' ? att.uploadedBy.username || att.uploadedBy.email : 'User'}
            </span>
          )}
        </div>
      </div>

      {/* Actions */}
      <div className="flex items-center gap-1 flex-shrink-0">
        {/* View */}
        {isImage(type) && (
          <a href={fileUrl} target="_blank" rel="noreferrer"
            className="p-1.5 rounded-lg text-slate-500 hover:text-cyan-400 hover:bg-cyan-400/10 transition-all"
            title="View image">
            <ZoomIn size={13} />
          </a>
        )}
        {(isVideo(type) || isAudio(type)) && (
          <button
            onClick={() => setPlaying(p => !p)}
            className="p-1.5 rounded-lg text-slate-500 hover:text-violet-400 hover:bg-violet-400/10 transition-all"
            title={playing ? 'Pause' : 'Play'}
          >
            {playing ? <Pause size={13} /> : <Play size={13} />}
          </button>
        )}
        {/* Download */}
        <a href={fileUrl} download={att.fileName}
          className="p-1.5 rounded-lg text-slate-500 hover:text-slate-200 hover:bg-white/10 transition-all"
          title="Download">
          <Download size={13} />
        </a>
        {/* Open */}
        <a href={fileUrl} target="_blank" rel="noreferrer"
          className="p-1.5 rounded-lg text-slate-500 hover:text-blue-400 hover:bg-blue-400/10 transition-all"
          title="Open in new tab">
          <ExternalLink size={13} />
        </a>
        {/* Remove */}
        {onRemove && (
          <button onClick={() => onRemove(att._id)}
            className="p-1.5 rounded-lg text-slate-600 hover:text-red-400 hover:bg-red-500/10 transition-all"
            title="Remove">
            <X size={13} />
          </button>
        )}
      </div>
    </div>
  );
}

// ── Media preview modal ───────────────────────────────────────────────────────
function MediaModal({ att, onClose }) {
  const fileUrl = getFileUrl(att.fileUrl);
  const isVid = isVideo(att.fileType);
  const isAud = isAudio(att.fileType);
  const isImg = isImage(att.fileType);
  const isP = isPDF(att.fileType);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm"
      onClick={onClose}>
      <div className="relative max-w-3xl w-full glass-strong rounded-3xl border border-white/10 overflow-hidden"
        onClick={e => e.stopPropagation()}>
        {/* Header */}
        <div className="flex items-center justify-between px-5 py-3 border-b border-white/5">
          <p className="text-sm font-semibold text-slate-200 font-bricolage truncate pr-4">{att.fileName}</p>
          <div className="flex items-center gap-2 flex-shrink-0">
            <a href={fileUrl} download={att.fileName}
              className="p-1.5 rounded-lg text-slate-500 hover:text-slate-200 hover:bg-white/10 transition-all">
              <Download size={14} />
            </a>
            <button onClick={onClose} className="p-1.5 rounded-lg text-slate-500 hover:text-slate-200 hover:bg-white/10 transition-all">
              <X size={14} />
            </button>
          </div>
        </div>
        {/* Body */}
        <div className="flex items-center justify-center bg-black/40" style={{ maxHeight: '60vh' }}>
          {isImg && (
            <img src={fileUrl} alt={att.fileName} className="max-w-full max-h-[60vh] object-contain" />
          )}
          {isVid && (
            <video
              src={fileUrl} controls autoPlay className="max-w-full max-h-[60vh]"
              style={{ outline: 'none' }}
            />
          )}
          {isAud && (
            <div className="w-full max-w-md py-8 px-6">
              <Music size={36} className="text-emerald-400 mx-auto mb-4" />
              <audio src={fileUrl} controls autoPlay className="w-full" />
            </div>
          )}
          {isP && (
            <iframe src={fileUrl} className="w-full h-[60vh]" title={att.fileName} />
          )}
          {isDocX(att.fileType) && (
            <div className="py-12 px-8 text-center">
              <FileText size={40} className="text-blue-400 mx-auto mb-3" />
              <p className="text-sm text-slate-300 font-bricolage mb-2">{att.fileName}</p>
              <a href={fileUrl} download={att.fileName}
                className="inline-flex items-center gap-2 px-5 py-2.5 rounded-xl bg-blue-500/10 hover:bg-blue-500/20 border border-blue-500/20 text-blue-400 text-sm font-semibold font-bricolage transition-all">
                <Download size={14} /> Download DOCX
              </a>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ── Multiple attachments list ─────────────────────────────────────────────────
export default function AttachmentDisplay({
  attachments = [],
  compact = false,
  onRemove,
  showUploader = false,
  title,
}) {
