import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Search, Loader2, Sparkles, Tag, X } from 'lucide-react';

const DEBOUNCE_MS = 350;
const MIN_QUERY   = 2;

// ─── Match Badge (exported for use in result lists) ───────────────────────────
export function MatchBadge({ matchType, matchPercentage }) {
  if (!matchType || matchType === 'none') return null;
  const isSemantic = matchType === 'semantic';
  return (
    <span className={`inline-flex items-center gap-1 text-[9px] font-bold uppercase tracking-wider font-bricolage px-1.5 py-0.5 rounded-full ${
      isSemantic
        ? 'bg-violet-500/15 text-violet-300 border border-violet-500/20'
        : 'bg-emerald-500/15 text-emerald-400 border border-emerald-500/20'
    }`}>
      <Sparkles size={8} />
      {matchPercentage}% match
    </span>
  );
}

// ─── SearchBar ─────────────────────────────────────────────────────────────────
//
// Supports two modes:
//
//  ✦ Controlled (onSearch):  Parent owns fetching. SearchBar is a dumb input.
//     <SearchBar onSearch={handleSearch} />
//     handleSearch = {(query) => { /* fetch + setState */ }}
//
//  ✦ Self-contained (onResults):  SearchBar fetches internally and streams
//     results to the parent for rendering.
//     <SearchBar onResults={(matches, type, clusters, insight) => {...}} />
//
// Both modes debounce and handle keyboard shortcuts identically.
//
export default function SearchBar({
  placeholder  = "Ask anything…",
  onSearch,      // controlled: parent fetches (legacy / Dashboard / RaiseTicket)
  onResults,     // smart:      SearchBar fetches, passes results up
  initialQuery = '',
  className    = '',
}) {
  const isControlled = Boolean(onSearch);

  const [query,          setQuery]          = useState(initialQuery);
  const [debouncedQuery, setDebouncedQuery] = useState(initialQuery);
  const [loading,        setLoading]        = useState(false);
  const [suggestions,    setSuggestions]    = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const abortRef = useRef(null);
  const inputRef  = useRef(null);

  // ── Debounce ──────────────────────────────────────────────────────────────
  useEffect(() => {
    const t = setTimeout(() => setDebouncedQuery(query), DEBOUNCE_MS);
    return () => clearTimeout(t);
  }, [query]);

  // ── Sync initialQuery ─────────────────────────────────────────────────────
  useEffect(() => {
    if (initialQuery !== query) setQuery(initialQuery);
  }, [initialQuery]);

  // ── Controlled: emit to parent, don't fetch internally ───────────────────
  useEffect(() => {
    if (!isControlled) return;
    if (debouncedQuery.length < MIN_QUERY) {
      onSearch && onSearch('');
      return;
    }
    onSearch && onSearch(debouncedQuery);
  }, [debouncedQuery, isControlled]);

  // ── Smart mode: internal fetch ────────────────────────────────────────────
  useEffect(() => {
    if (isControlled || debouncedQuery.length < MIN_QUERY) {
      setLoading(false);
      return;
    }

    setLoading(true);
    if (abortRef.current) abortRef.current.abort();
    const controller = new AbortController();
    abortRef.current = controller;

    const tid = setTimeout(async () => {
      try {
        const res = await fetch(
          `/api/search?q=${encodeURIComponent(debouncedQuery)}&type=faq`,
          { signal: controller.signal }
        );
        const data = await res.json();
        if (!controller.signal.aborted) {
          setLoading(false);
          onResults && onResults(
            data.matches  || [],
            data.matchType || 'none',
            data.clusters  || [],
            data.insight   || ''
          );
        }
      } catch {
        if (!controller.signal.aborted) setLoading(false);
      }
    }, DEBOUNCE_MS + 80);

    return () => { clearTimeout(tid); controller.abort(); };
  }, [debouncedQuery, isControlled]);

  // ── Autocomplete suggestions ──────────────────────────────────────────────
  useEffect(() => {
    if (debouncedQuery.length < MIN_QUERY) { setSuggestions([]); return; }
    const controller = new AbortController();
    const tid = setTimeout(async () => {
      try {
        const res = await fetch(
          `/api/search/suggest?q=${encodeURIComponent(debouncedQuery)}`,
          { signal: controller.signal }
        );
        const data = await res.json();
        if (!controller.signal.aborted) setSuggestions(data.suggestions || []);
      } catch {
        // abort is expected
      }
    }, 180);
    return () => { clearTimeout(tid); controller.abort(); };
  }, [debouncedQuery]);

  const handleClear = useCallback(() => {
    setQuery('');
    setSuggestions([]);
    setDebouncedQuery('');
    setShowSuggestions(false);
    if (isControlled) onSearch && onSearch('');
    else onResults && onResults([], 'none', [], '');
    inputRef.current?.focus();
  }, [isControlled, onSearch, onResults]);

  const handleSuggestionClick = useCallback((s) => {
    setQuery(s);
    setDebouncedQuery(s);
    setShowSuggestions(false);
    // Force an immediate search emit in controlled mode
    if (isControlled) onSearch && onSearch(s);
  }, [isControlled, onSearch]);

  const handleKeyDown = useCallback((e) => {
    if (e.key === 'Escape') handleClear();
    if (e.key === 'Enter')  setShowSuggestions(false);
  }, [handleClear]);

  const inputClasses = [
    'w-full bg-white/5 border border-white/10 hover:border-white/20',
    'focus:border-violet-500/50 focus:ring-2 focus:ring-violet-500/20',
    'rounded-2xl py-4 pl-14 pr-12 text-slate-100 placeholder-slate-500',
    'outline-none transition-all duration-300 shadow-inner font-medium text-lg',
    loading ? 'text-slate-200' : '',
  ].join(' ');

  return (
    <div className={`relative group ${className}`}>
      {/* Decorative gradient glow */}
      <div className="absolute -inset-0.5 bg-gradient-to-r from-violet-500/10 via-indigo-500/10 to-teal-500/10 rounded-2xl blur opacity-0 group-hover:opacity-100 transition duration-500 pointer-events-none" />

      <div className="relative flex items-center w-full">
        {/* Left icon */}
        <div className="absolute left-5 flex items-center justify-center text-slate-400 pointer-events-none">
          {loading
            ? <Loader2 className="w-5 h-5 animate-spin text-violet-400" />
            : <Search className="w-5 h-5" strokeWidth={2.5} />
          }
        </div>

        <input
          ref={inputRef}
          type="text"
          placeholder={placeholder}
          value={query}
          onChange={e => { setQuery(e.target.value); setShowSuggestions(true); }}
          onFocus={() => setShowSuggestions(true)}
          onBlur={() => setTimeout(() => setShowSuggestions(false), 180)}
          onKeyDown={handleKeyDown}
          className={inputClasses}
          autoComplete="off"
          spellCheck="false"
        />

        {/* Right slot: clear or loading dots */}
        {!loading && query && (
          <button
            type="button"
            onClick={handleClear}
            className="absolute right-5 text-slate-500 hover:text-slate-300 transition-colors p-1"
          >
            <X size={15} />
          </button>
        )}
        {loading && (
          <span className="absolute right-5 flex gap-0.5 items-center">
            {[0, 120, 240].map(delay => (
              <span
                key={delay}
                className="w-1.5 h-1.5 rounded-full bg-violet-400 animate-bounce"
                style={{ animationDelay: `${delay}ms` }}
              />
            ))}
          </span>
        )}
      </div>

      {/* Autocomplete suggestions dropdown */}
      {showSuggestions && suggestions.length > 0 && (
        <ul className="absolute top-full left-0 right-0 mt-2 bg-[#13111c] border border-white/10 rounded-xl shadow-2xl overflow-hidden z-50">
          {suggestions.map((s, i) => (
            <li key={i}>
              <button
                type="button"
                onMouseDown={() => handleSuggestionClick(s)}
                className="w-full flex items-center gap-3 px-4 py-3 text-left text-sm text-slate-300 hover:bg-white/5 transition-colors"
              >
                <Search size={13} className="text-slate-500 flex-shrink-0" />
                <span>{s}</span>
                <Tag size={11} className="text-slate-600 ml-auto flex-shrink-0" />
              </button>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axiosClient from '../api/axiosClient';
import { Shield, ShieldCheck, Ticket } from 'lucide-react';

export default function StaffToolsNav({ close = () => {} }) {
  const navigate = useNavigate();
  const [pendingAssignedCount, setPendingAssignedCount] = useState(0);
  const role = localStorage.getItem('role');

  useEffect(() => {
    if (['admin', 'superadmin', 'mentor'].includes(role)) {
      axiosClient.get('/admin/personal-tickets')
        .then(res => {
          const count = res.data.tickets.filter(t => t.status === 'pending' || t.status === 'assigned').length;
          setPendingAssignedCount(count);
        })
        .catch(err => {
          console.error('[Assigned Work Fetch Error]', err);
        });
    }
  }, [role]);

  if (!['admin', 'superadmin', 'moderator', 'mentor'].includes(role)) {
    return null;
  }

  return (
    <div className="pt-3 space-y-2 border-t border-white/5 mt-3">
      <p className="px-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest font-bricolage mb-1">Staff Tools</p>

      {['admin', 'superadmin'].includes(role) && (
         <button onClick={() => { navigate('/admin'); close(); }} className="sidebar-button sidebar-button-normal w-full">
           <Shield size={18} className="text-amber-400" /> Admin Dashboard
         </button>
      )}

      {['admin', 'superadmin', 'moderator'].includes(role) && (
         <button onClick={() => { navigate('/admin?section=queue'); close(); }} className="sidebar-button sidebar-button-normal w-full">
           <ShieldCheck size={18} className="text-blue-400" /> Moderator Center
         </button>
      )}

      {['admin', 'superadmin', 'mentor'].includes(role) && (
         <button onClick={() => { navigate('/admin?section=personal'); close(); }} className="sidebar-button sidebar-button-normal flex justify-between w-full items-center">
           <div className="flex items-center gap-3"><Ticket size={18} className="text-emerald-400" /> Assigned Work</div>
           {pendingAssignedCount > 0 && (
             <span className="bg-red-500 text-white text-[10px] font-bold px-2 py-0.5 rounded-full shadow-md">
               {pendingAssignedCount}
             </span>
           )}
         </button>
      )}
    </div>
  );
}

import React from 'react';
import { useBannedClass } from '../hooks/useBannedTheme';

export default function StatusBadge({ variant = 'gray', icon: Icon, children, className = '' }) {
  const { badgeYellow } = useBannedClass();

  const variants = {
    yellow: badgeYellow,
    purple: "bg-purple-100 text-purple-900 border-purple-300 dark:bg-purple-500/20 dark:text-purple-400 dark:border-purple-500/30",
    green: "bg-emerald-100 text-emerald-900 border-emerald-300 dark:bg-emerald-500/20 dark:text-emerald-400 dark:border-emerald-500/30",
    red: "bg-rose-100 text-rose-900 border-rose-300 dark:bg-rose-500/20 dark:text-rose-400 dark:border-rose-500/30",
    gray: "bg-slate-100 text-slate-900 border-slate-300 dark:bg-slate-500/20 dark:text-slate-400 dark:border-slate-500/30",
  };

  const selectedVariant = variants[variant] || variants.gray;

  return (
    <div className={`inline-flex items-center justify-center gap-1.5 px-3 py-1.5 rounded-xl border shadow-sm text-xs font-bold whitespace-nowrap font-bricolage transition-all hover:brightness-95 dark:hover:brightness-110 ${selectedVariant} ${className}`}>
      {Icon && <Icon size={14} />}
      {children}
    </div>
  );
}

import React from 'react';
import { motion } from 'framer-motion';
import { Check, Hourglass, UserCheck, ShieldCheck, CheckCircle } from 'lucide-react';

const ICONS = {
  submitted: Check,
  under_review: Hourglass,
  assigned_to_peer: UserCheck,
  admin_review: ShieldCheck,
  resolved: CheckCircle
};

const LABELS = {
  submitted: 'Submitted',
  under_review: 'Under Review',
  assigned_to_peer: 'Assigned to Peer',
  admin_review: 'Admin Review',
  resolved: 'Resolved'
};

export default function StatusStage({ stage, currentStatus, index, totalStages }) {
  const STAGE_ORDER = ['submitted', 'under_review', 'assigned_to_peer', 'admin_review', 'resolved'];

  const currentIndex = STAGE_ORDER.indexOf(currentStatus);
  const stageIndex = STAGE_ORDER.indexOf(stage);

  const isCompleted = stageIndex < currentIndex;
  const isActive = stageIndex === currentIndex;
  const isPending = stageIndex > currentIndex;

  const Icon = ICONS[stage] || Check;
  const label = LABELS[stage] || stage;

  return (
    <div className="relative flex flex-row sm:flex-col items-center sm:flex-1 z-10 w-full sm:w-auto gap-4 sm:gap-0">
      <motion.div 
        initial={{ scale: 0.8, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        transition={{ delay: index * 0.1, type: 'spring', stiffness: 200 }}
        className={`w-10 h-10 rounded-full flex items-center justify-center border transition-all duration-500 shadow-sm shrink-0
          ${isActive 
            ? 'bg-emerald-500 border-emerald-400 text-white shadow-md scale-110' 
            : isCompleted 
              ? 'bg-emerald-600 border-emerald-500 text-white dark:bg-emerald-700' 
              : 'bg-white/50 border-slate-200 text-slate-400 dark:border-white/10 dark:bg-black/20 dark:text-slate-500'}`}
      >
        <Icon size={16} strokeWidth={2.5} className={isActive ? 'animate-pulse' : ''} />
      </motion.div>
      <span className={`sm:mt-3 text-[13px] font-bold font-bricolage text-left sm:text-center transition-colors duration-500 tracking-wide
        ${isActive 
          ? 'text-emerald-700 dark:text-emerald-400' 
          : isCompleted 
            ? 'text-slate-700 dark:text-slate-300' 
            : 'text-slate-400 dark:text-slate-500'}`}
      >
        {label}
      </span>
    </div>
  );
}

import React from 'react';
import { motion } from 'framer-motion';
import StatusStage from './StatusStage';

export default function StatusTimeline({ currentStatus }) {
  const STAGE_ORDER = ['submitted', 'under_review', 'assigned_to_peer', 'admin_review', 'resolved'];

  // Treat 'pending' as 'submitted' for the UI
  const normalizedStatus = currentStatus === 'pending' ? 'submitted' : currentStatus;

  const currentIndex = STAGE_ORDER.indexOf(normalizedStatus) !== -1 ? STAGE_ORDER.indexOf(normalizedStatus) : 0;

  return (
    <div className="glass-card rounded-3xl p-6 sm:p-8 w-full border border-emerald-100/50 dark:border-white/5 bg-white/40 dark:bg-black/10 backdrop-blur-xl shadow-sm mb-6 relative overflow-hidden">
      <div className="flex items-center gap-2 mb-8 md:mb-10">
        <div className="p-1.5 rounded-lg bg-emerald-500/10 text-emerald-600 dark:text-emerald-400">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="w-4 h-4">
            <path strokeLinecap="round" strokeLinejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" />
          </svg>
        </div>
        <h3 className="text-sm font-bold font-bricolage text-slate-700 dark:text-slate-200">Real-Time Status</h3>
      </div>

      <div className="relative flex flex-col sm:flex-row justify-between items-start sm:items-center w-full mt-4 pb-2 gap-8 sm:gap-0">
        {/* Background Line */}
        <div className="absolute left-[19px] sm:left-[10%] top-[20px] bottom-[20px] sm:bottom-auto sm:right-[10%] w-[2px] sm:w-auto sm:h-[2px] bg-emerald-100 dark:bg-white/10 -z-0" />

        {/* Animated Progress Line */}
        <motion.div 
          initial={{ height: 0, width: 0 }}
          animate={{ 
            height: typeof window !== 'undefined' && window.innerWidth < 640 ? `${(currentIndex / (STAGE_ORDER.length - 1)) * 100}%` : '2px',
            width: typeof window !== 'undefined' && window.innerWidth >= 640 ? `${(currentIndex / (STAGE_ORDER.length - 1)) * 80 + 10}%` : '2px'
          }}
          transition={{ duration: 1, ease: "easeInOut" }}
          className="absolute left-[19px] sm:left-[10%] top-[20px] sm:top-[20px] w-[2px] sm:w-auto sm:h-[2px] bg-gradient-to-b sm:bg-gradient-to-r from-emerald-400 to-emerald-600 shadow-[0_0_10px_rgba(52,211,153,0.5)] -z-0" 
        />

        {STAGE_ORDER.map((stage, index) => (
          <StatusStage 
            key={stage} 
            stage={stage} 
            currentStatus={normalizedStatus} 
            index={index} 
            totalStages={STAGE_ORDER.length} 
          />
        ))}
      </div>
    </div>
  );
}

