import React, { useState, useEffect, useCallback } from 'react';
import axiosClient from '../api/axiosClient';
import toast from 'react-hot-toast';
import { Pizza, Settings2, Eye, EyeOff, BarChart2, RefreshCw, ChevronRight, Loader2 } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

// ─── Constants ────────────────────────────────────────────────────────────────

const PIZZA_OPTIONS = [0, 1, 3, 5, 6, 10];

// ─── Sub-components ───────────────────────────────────────────────────────────

function Toggle({ label, description, value, onChange, disabled }) {
  return (
    <label className={`flex items-center justify-between gap-4 py-4 border-b border-white/[0.05] last:border-0 cursor-pointer ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}>
      <div className="flex-1 min-w-0">
        <div className="text-sm font-semibold text-slate-200 leading-snug">{label}</div>
        {description && (
          <div className="text-xs text-slate-500 mt-0.5 leading-relaxed">{description}</div>
        )}
      </div>
      <button
        type="button"
        role="switch"
        aria-checked={value}
        disabled={disabled}
        onClick={() => !disabled && onChange(!value)}
        className={[
          'relative inline-flex h-6 w-11 flex-shrink-0 rounded-full border-2 border-transparent',
          'transition-colors duration-200 ease-in-out',
          'focus:outline-none focus-visible:ring-2 focus-visible:ring-purple-500/50',
          value ? 'bg-emerald-500/80' : 'bg-white/10',
        ].join(' ')}
      >
        <span
          className={[
            'pointer-events-none inline-block h-5 w-5 rounded-full bg-white shadow-lg transform',
            'transition duration-200 ease-in-out',
            value ? 'translate-x-5' : 'translate-x-0',
          ].join(' ')}
        />
      </button>
    </label>
  );
}

function SectionCard({ icon: Icon, title, badge, children, footer }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 12 }}
      animate={{ opacity: 1, y: 0 }}
      className="glass-strong rounded-2xl overflow-hidden border border-white/5 shadow-xl"
    >
      {/* Header */}
      <div className="flex items-center gap-3 px-6 py-5 border-b border-white/[0.05] bg-white/[0.005]">
        <div className="flex items-center justify-center w-8 h-8 rounded-lg bg-white/5 border border-white/10">
          <Icon size={15} className="text-slate-300" />
        </div>
        <span className="text-sm font-bold font-bricolage text-slate-100">{title}</span>
        {badge && (
          <span className="ml-auto text-[10px] font-bold font-bricolage px-2 py-0.5 rounded-full bg-white/5 border border-white/10 text-slate-400 uppercase tracking-widest">
            {badge}
          </span>
        )}
      </div>

      {/* Body */}
      <div className="px-6">{children}</div>

      {/* Footer */}
      {footer && (
        <div className="px-6 py-4 border-t border-white/[0.05] bg-white/[0.005]">
          {footer}
        </div>
      )}
    </motion.div>
  );
}

// ─── Main Component ───────────────────────────────────────────────────────────

export default function AdminSettingsTab() {
  // ── Settings state ────────────────────────────────────────────────────────
  const [settings, setSettings] = useState({
    defaultPizzaSlices: 1,
    publicFAQEnabled: true,
    guestFAQSearchEnabled: true,
    guestAnalyticsTrackingEnabled: false,
    updatedBy: '—',
    updatedAt: null,
  });

  // ── Edit state ─────────────────────────────────────────────────────────────
  const [selectedPizzaSlices, setSelectedPizzaSlices]   = useState(null); // null = not changed
  const [savingPizza,  setSavingPizza]  = useState(false);
  const [savingToggles, setSavingToggles] = useState(false);
  const [migrating, setMigrating]       = useState(false);
  const [migrateResult, setMigrateResult] = useState(null); // { count, amount }
  const [loading, setLoading]           = useState(true);

  // ── Load settings ─────────────────────────────────────────────────────────
  const fetchSettings = useCallback(async () => {
    try {
      const res = await axiosClient.get('/admin/settings');
      const s = res.data.settings;
      setSettings(s);
      setSelectedPizzaSlices(null); // reset pending selection
    } catch (err) {
      toast.error('Failed to load settings.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchSettings(); }, [fetchSettings]);

  // ── Pizza slice save ───────────────────────────────────────────────────────
  const handleSavePizza = async () => {
    if (selectedPizzaSlices === null) return;
    setSavingPizza(true);
    try {
      const res = await axiosClient.patch('/admin/settings/pizza', {
        defaultPizzaSlices: selectedPizzaSlices,
      });
      toast.success(res.data.message || 'Pizza settings updated.');
      setSettings(prev => ({
        ...prev,
        defaultPizzaSlices: selectedPizzaSlices,
        updatedBy: 'you',
        updatedAt: new Date().toISOString(),
      }));
      setSelectedPizzaSlices(null);
    } catch (err) {
      toast.error(err.response?.data?.error || 'Failed to update pizza settings.');
    } finally {
      setSavingPizza(false);
    }
  };

  // ── Toggle save ───────────────────────────────────────────────────────────
  const [pendingToggles, setPendingToggles] = useState({});

  const handleToggleChange = (key, value) => {
    setPendingToggles(prev => ({ ...prev, [key]: value }));
  };

  const handleSaveToggles = async () => {
    setSavingToggles(true);
    try {
      const res = await axiosClient.patch('/admin/settings/public-faq', pendingToggles);
      toast.success(res.data.message || 'Public FAQ settings updated.');
      setSettings(prev => ({
        ...prev,
        ...pendingToggles,
        updatedBy: 'you',
        updatedAt: new Date().toISOString(),
      }));
      setPendingToggles({});
    } catch (err) {
      toast.error(err.response?.data?.error || 'Failed to update settings.');
    } finally {
      setSavingToggles(false);
    }
  };

  // ── Apply migration ────────────────────────────────────────────────────────
  const handleApplyMigration = async () => {
    const confirmed = window.confirm(
      'This will grant the current default pizza slice amount to every user who has 0 slices.\n\n' +
      'Already-initialised users will not be affected. Continue?',
    );
    if (!confirmed) return;

    setMigrating(true);
    setMigrateResult(null);
    try {
      const res = await axiosClient.post('/admin/settings/pizza/apply-migration');
      setMigrateResult({ count: res.data.migratedCount, amount: res.data.amount });
      toast.success(res.data.message);
    } catch (err) {
      toast.error(err.response?.data?.error || 'Migration failed.');
    } finally {
      setMigrating(false);
    }
  };

  // ── Helpers ────────────────────────────────────────────────────────────────
  const hasPendingToggles = Object.keys(pendingToggles).length > 0;

  const fmtDate = (iso) => {
    if (!iso) return '—';
    try {
      return new Intl.DateTimeFormat('en-GB', {
        day: '2-digit', month: 'short', year: 'numeric',
        hour: '2-digit', minute: '2-digit',
      }).format(new Date(iso));
    } catch { return iso; }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-24">
        <Loader2 size={24} className="animate-spin text-slate-500" />
      </div>
    );
  }

  const currentPizza    = selectedPizzaSlices !== null ? selectedPizzaSlices : settings.defaultPizzaSlices;
  const effectiveToggles = { ...settings, ...pendingToggles };

  return (
    <div className="space-y-8 max-w-2xl">

      {/* ── 1. Pizza Slice Configuration ──────────────────────────────────── */}
      <SectionCard
        icon={Pizza}
        title="Pizza Slice Configuration"
        badge="Economy"
        footer={
          <div className="flex items-center justify-between gap-4">
            {/* Last updated meta */}
            <div className="text-xs text-slate-500">
              <span>Last updated </span>
              <span className="text-slate-400">{fmtDate(settings.updatedAt)}</span>
              {settings.updatedBy && (
                <>
                  <span className="mx-1">·</span>
                  <span className="text-slate-400">by {settings.updatedBy}</span>
                </>
              )}
            </div>

            {/* Save button */}
            <button
              type="button"
              disabled={selectedPizzaSlices === null || savingPizza}
              onClick={handleSavePizza}
              className={[
                'flex items-center gap-2 px-5 py-2 rounded-xl text-sm font-semibold font-bricolage',
                'transition-all duration-200',
                selectedPizzaSlices !== null && !savingPizza
                  ? 'bg-emerald-500/80 hover:bg-emerald-500 text-white shadow-lg shadow-emerald-500/20 cursor-pointer'
                  : 'bg-white/5 text-slate-500 cursor-not-allowed',
              ].join(' ')}
            >
              {savingPizza
                ? <><Loader2 size={13} className="animate-spin" /> Saving…</>
                : <><ChevronRight size={14} /> Apply</>
              }
            </button>
          </div>
        }
      >
        {/* Current value display */}
        <div className="py-5 border-b border-white/[0.05]">
          <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-3 font-bricolage">
            Current Default
          </div>
          <div className="flex items-center gap-3">
            <span className="text-3xl font-black font-bricolage text-slate-100">
              {settings.defaultPizzaSlices}
            </span>
            <span className="text-slate-400 text-sm font-medium">pizza slice{settings.defaultPizzaSlices !== 1 ? 's' : ''}</span>
          </div>
        </div>

        {/* Slice selector */}
        <div className="py-5">
          <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-3 font-bricolage">
            New Default — select a value
          </div>
          <div className="grid grid-cols-6 gap-2">
            {PIZZA_OPTIONS.map(val => (
              <button
                key={val}
                type="button"
                onClick={() => setSelectedPizzaSlices(val)}
                className={[
                  'py-3 rounded-xl text-sm font-bold font-bricolage border transition-all duration-150',
                  currentPizza === val
                    ? 'bg-emerald-500/20 border-emerald-500/40 text-emerald-300 shadow-inner'
                    : 'bg-white/[0.02] border-white/[0.08] text-slate-400 hover:border-white/[0.15] hover:text-slate-200 cursor-pointer',
                ].join(' ')}
              >
                {val}
              </button>
            ))}
          </div>
          <p className="text-xs text-slate-600 mt-3">
            Allowed values: {PIZZA_OPTIONS.join(', ')}
          </p>
        </div>
      </SectionCard>

      {/* ── 2. Public FAQ Toggles ─────────────────────────────────────────── */}
      <SectionCard
        icon={Settings2}
        title="Public FAQ Access"
        footer={
          hasPendingToggles && (
            <div className="flex justify-end">
              <button
                type="button"
                disabled={savingToggles}
                onClick={handleSaveToggles}
                className="flex items-center gap-2 px-5 py-2 rounded-xl text-sm font-semibold font-bricolage bg-emerald-500/80 hover:bg-emerald-500 text-white shadow-lg shadow-emerald-500/20 transition-all duration-200 cursor-pointer"
              >
                {savingToggles
                  ? <><Loader2 size={13} className="animate-spin" /> Saving…</>
                  : <><ChevronRight size={14} /> Save Changes</>
                }
              </button>
            </div>
          )
        }
      >
        <Toggle
          label="Public FAQ Enabled"
          description="Allow guests to browse and read the FAQ knowledge base."
          value={effectiveToggles.publicFAQEnabled}
          onChange={v => handleToggleChange('publicFAQEnabled', v)}
        />
        <Toggle
          label="Guest FAQ Search"
          description="Allow unauthenticated users to search FAQs."
          value={effectiveToggles.guestFAQSearchEnabled}
          onChange={v => handleToggleChange('guestFAQSearchEnabled', v)}
        />
        <Toggle
          label="Guest Analytics Tracking"
          description="Record view counts and basic engagement from guests (does not track identities)."
          value={effectiveToggles.guestAnalyticsTrackingEnabled}
          onChange={v => handleToggleChange('guestAnalyticsTrackingEnabled', v)}
        />
      </SectionCard>

      {/* ── 3. Apply To Existing Users ───────────────────────────────────── */}
      <SectionCard
        icon={RefreshCw}
        title="Apply to Existing Users"
        badge="Migration"
      >
        <div className="py-5 space-y-4">
          <p className="text-sm text-slate-400 leading-relaxed">
            Grants the current default pizza slice amount (
            <strong className="text-slate-200">{settings.defaultPizzaSlices}</strong>) to every
            user who currently has{' '}
            <strong className="text-slate-200">0 slices</strong>.
          </p>

          <div className="flex items-start gap-3 p-4 rounded-xl bg-amber-500/5 border border-amber-500/15">
            <div className="mt-0.5">
              <Eye size={15} className="text-amber-400/70" />
            </div>
            <p className="text-xs text-amber-300/70 leading-relaxed">
              <strong>Warning:</strong> Only affects users who have never received
              initialization slices. Already-initialised users (any non-zero balance)
              are skipped automatically.
            </p>
          </div>

          {/* Migration result */}
          <AnimatePresence>
            {migrateResult && (
              <motion.div
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: 'auto' }}
                exit={{ opacity: 0, height: 0 }}
                className="flex items-center gap-3 p-4 rounded-xl bg-emerald-500/5 border border-emerald-500/15 text-sm text-emerald-300/80"
              >
                <BarChart2 size={15} className="flex-shrink-0" />
                Applied {migrateResult.amount} pizza slice{migrateResult.amount !== 1 ? 's' : ''} to{' '}
                <strong>{migrateResult.count}</strong> eligible user{migrateResult.count !== 1 ? 's' : ''}.
              </motion.div>
            )}
          </AnimatePresence>

          <button
            type="button"
            disabled={migrating}
            onClick={handleApplyMigration}
            className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-semibold font-bricolage bg-white/5 hover:bg-white/10 border border-white/10 text-slate-200 transition-all duration-200 cursor-pointer disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {migrating
              ? <><Loader2 size={13} className="animate-spin" /> Migrating…</>
              : <><RefreshCw size={13} /> Apply To Existing Users</>
            }
          </button>
        </div>
      </SectionCard>

    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import axiosClient from '../api/axiosClient';
import { Book, Tag, ChevronRight, Search } from 'lucide-react';

function normalizeCategory(cat) {
  if (!cat) return 'General';
  if (typeof cat === 'object') return cat.name || 'General';
  return cat.charAt(0).toUpperCase() + cat.slice(1);
}

export default function CategoriesPage() {
  const navigate = useNavigate();
  const location = useLocation();
  const [faqs, setFaqs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [highlight, setHighlight] = useState(null);

  const isLoggedIn = Boolean(localStorage.getItem('token'));

  useEffect(() => {
    if (location.state?.highlight) setHighlight(location.state.highlight);
    axiosClient.get('/faqs?status=published', { timeout: 10000 })
      .then(r => setFaqs(r.data.faqs || []))
      .catch(() => setFaqs([]))
      .finally(() => setLoading(false));
  }, [location.state]);

  // Group by category
  const byCategory = {};
  for (const faq of faqs) {
    const cat = normalizeCategory(faq.category || faq.categoryId?.name || faq.categoryId);
    if (!byCategory[cat]) byCategory[cat] = [];
    byCategory[cat].push(faq);
  }

  const categories = Object.entries(byCategory)
    .map(([cat, catFaqs]) => ({
      name: cat,
      count: catFaqs.length,
      recent: [...catFaqs].sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt))[0],
    }))
    .sort((a, b) => b.count - a.count);

  const filtered = searchQuery
    ? categories.filter(c => c.name.toLowerCase().includes(searchQuery.toLowerCase()))
    : categories;

  function openFaq(faq) {
    navigate(`/faq/${faq._id}`, { state: { faq } });
  }

  return (
    <div className="min-h-screen bg-mesh font-inter">
      <header className="sticky top-0 z-30 glass-strong border-b border-white/5">
        <div className="max-w-5xl mx-auto px-6 h-16 flex items-center justify-between">
          <button onClick={() => navigate('/')} className="flex items-center gap-2.5 hover:opacity-80">
            <div className="w-8 h-8 rounded-xl bg-white/5 border border-white/10 flex items-center justify-center">
              <Book size={16} className="text-slate-300" strokeWidth={2} />
            </div>
            <span className="font-bold font-bricolage text-lg text-slate-100">FAQ Hive</span>
          </button>
          <div className="flex items-center gap-2">
            {isLoggedIn
              ? <button onClick={() => navigate('/dashboard')} className="px-4 py-2 rounded-xl text-sm font-semibold bg-white/5 hover:bg-white/10 text-slate-200 font-bricolage border border-white/5">Dashboard</button>
              : <>
                  <button onClick={() => navigate('/login')} className="px-4 py-2 rounded-xl text-sm font-semibold text-slate-300 hover:text-slate-100 font-bricolage">Sign In</button>
                  <button onClick={() => navigate('/register')} className="px-4 py-2 rounded-xl text-sm font-semibold bg-white/10 hover:bg-white/15 text-slate-100 font-bricolage border border-white/10">Create Account</button>
                </>
            }
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-6 py-10">
        <h1 className="text-2xl font-bold font-bricolage text-slate-100 mb-2 tracking-tight">Categories</h1>
        <p className="text-sm text-slate-500 mb-6 font-bricolage">{categories.length} categories · {faqs.length} total FAQs</p>

        {/* Search */}
        <div className="relative mb-7">
          <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" />
          <input
            type="text" value={searchQuery} onChange={e => setSearchQuery(e.target.value)}
            placeholder="Filter categories…" autoFocus
            className="w-full pl-12 pr-4 py-3.5 rounded-2xl bg-white/[0.06] border border-white/10 text-slate-100 placeholder-slate-600 text-sm focus:outline-none focus:border-amber-500/40 transition-all font-inter"
          />
        </div>

        {loading ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {[...Array(6)].map((_, i) => (
              <div key={i} className="h-28 rounded-2xl bg-white/[0.03] border border-white/5 animate-pulse" />
            ))}
          </div>
        ) : filtered.length === 0 ? (
          <div className="text-center py-20 text-slate-500 font-bricolage">No categories match "{searchQuery}"</div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {filtered.map(cat => (
              <button
                key={cat.name}
                onClick={() => navigate('/faqs', { state: { category: cat.name } })}
                className={`glass-card rounded-2xl p-5 text-left hover:bg-white/[0.04] border-white/5 transition-all group ${highlight === cat.name ? 'ring-1 ring-amber-500/40' : ''}`}
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-2">
                      <Tag size={13} className="text-violet-400" />
                      <h3 className="font-bold font-bricolage text-slate-100 text-sm">{cat.name}</h3>
                      {highlight === cat.name && (
                        <span className="text-[10px] bg-amber-500/10 text-amber-400 px-1.5 py-0.5 rounded font-bold font-bricolage">selected</span>
                      )}
                    </div>
                    <p className="text-xs text-slate-500 font-bricolage mb-3">{cat.count} {cat.count === 1 ? 'FAQ' : 'FAQs'}</p>
                    {cat.recent && (
                      <p className="text-xs text-slate-600 font-bricolage line-clamp-2 leading-relaxed">
                        {cat.recent.canonicalQuestion || cat.recent.question || cat.recent.title}
                      </p>
                    )}
                  </div>
                  <ChevronRight size={16} className="text-slate-600 group-hover:text-slate-400 flex-shrink-0 mt-1 transition-colors" />
                </div>
              </button>
            ))}
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axiosClient from '../api/axiosClient';
import toast from 'react-hot-toast';
import {
  MessageSquare, Wallet, LogOut, X, Sparkles, Check, Plus, Menu, Pizza
, Book } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import GoldenTicketIcon from '../components/GoldenTicketIcon';
import BannedUserBanner from '../components/BannedUserBanner';
import ThemeToggle from '../components/ThemeToggle';
import { formatPizzas } from '../utils/pizzaFormatter';
import Avatar from '../components/Avatar';
import CategoryDropdown, { FALLBACK_CATEGORIES } from '../components/CategoryDropdown';
import AttachmentUpload from '../components/AttachmentUpload';
import { useBannedTheme } from '../hooks/useBannedTheme';
import StaffToolsNav from '../components/StaffToolsNav';

export default function ContributeFAQ() {
  const [user, setUser] = useState(null);

  useBannedTheme(user);
  const navigate = useNavigate();

  // Contribution state
  const [categories, setCategories] = useState([]);
  const [contribCategory, setContribCategory] = useState('');
  const [contribCustomCategory, setContribCustomCategory] = useState('');
  const [contribQuestion, setContribQuestion] = useState('');
  const [contribAnswer, setContribAnswer] = useState('');
  const [isContributing, setIsContributing] = useState(false);
  const [contribResult, setContribResult] = useState(null); // { generatedQuestion, generatedAnswer }
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [contribAttachments, setContribAttachments] = useState([]);

  useEffect(() => {
    axiosClient.get('/auth/me').then(r => setUser(r.data.user)).catch(() => { });
    // Fetch categories dynamically
    axiosClient.get('/faqs/categories')
      .then(r => {
        const names = r.data.categories.map(c => c.name);
        setCategories(names.length > 0 ? names : FALLBACK_CATEGORIES);
      })
      .catch(() => setCategories(FALLBACK_CATEGORIES));
  }, []);

  const handleContribute = async (e) => {
    e.preventDefault();
    if (!contribCategory) return toast.error('Please select a category');
    if (contribCategory === 'Other' && (!contribCustomCategory || !contribCustomCategory.trim())) {
      return toast.error('Please specify your custom category');
    }
    if (!contribQuestion.trim() || contribQuestion.trim().split(' ').length < 3)
      return toast.error('Question must be at least 3 words');
    if (!contribAnswer.trim() || contribAnswer.trim().split(' ').length < 5)
      return toast.error('Answer must be at least 5 words');

    setIsContributing(true);
    setContribResult(null);
    try {
      const res = await axiosClient.post('/faqs/contribute', {
        category: contribCategory,
        customCategory: contribCustomCategory,
        question: contribQuestion,
        answer: contribAnswer,
        attachments: contribAttachments,
      });
      setContribResult(res.data.contribution);
      toast.success('FAQ contributed! Thank you for helping the community.');
      setContribQuestion('');
      setContribAnswer('');
      setContribCategory('');
      setContribCustomCategory('');
      setContribAttachments([]);
    } catch (err) {
      if (err.response?.data?.duplicate) {
        toast.error('A similar FAQ already exists in the knowledge base.');
      } else {
        toast.error(err.response?.data?.message || 'Contribution failed');
      }
    } finally {
      setIsContributing(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('role');
    navigate('/login');
  };

  const NavItem = ({ icon: Icon, label, active, onClick }) => (
    <button onClick={onClick}
      className={`sidebar-button ${active ? 'sidebar-button-normal active' : 'sidebar-button-normal'}`}
    >
      <Icon size={18} strokeWidth={active ? 2.2 : 1.8} className="flex-shrink-0" />
      <span>{label}</span>
    </button>
  );

  const navSection = (close = () => { }) => (
    <nav className="space-y-1.5">
      <NavItem icon={Book} label="FAQ" active={false} onClick={() => { navigate('/faqs'); close(); }} />
      <NavItem icon={MessageSquare} label="Once Asked Questions" active={false} onClick={() => { navigate('/discussions'); close(); }} />
      <NavItem icon={Wallet} label="Wallet" active={false} onClick={() => { navigate('/wallet'); close(); }} />
      <div className="pt-3 space-y-2 border-t border-white/5 mt-3">
        <button onClick={() => { navigate('/raise-ticket'); close(); }}
          className="sidebar-button sidebar-button-normal"
        >
          <Plus size={18} strokeWidth={2.5} className="flex-shrink-0" /> Raise Ticket
        </button>
        <button onClick={() => { navigate('/contribute-faq'); close(); }}
          className="sidebar-button sidebar-button-normal active"
        >
          <Sparkles size={18} strokeWidth={2.5} className="flex-shrink-0" /> Contribute FAQ
        </button>
        <button onClick={() => { navigate('/golden-ticket'); close(); }}
          className="sidebar-button sidebar-button-golden group"
        >
          <div className="absolute inset-0 -translate-x-full group-hover:animate-[shimmer_1.5s_infinite] bg-gradient-to-r from-transparent via-white/40 to-transparent skew-x-12"></div>
          <GoldenTicketIcon size={18} className="flex-shrink-0 drop-shadow-md" />
          <span className="drop-shadow-md tracking-wide">Golden Ticket</span>
        </button>
      </div>
      <StaffToolsNav close={close} />
    </nav>
  );

  return (
    <div data-banned={user?.isBanned ? "true" : "false"} className="flex h-screen bg-mesh overflow-hidden font-inter text-slate-300">
      {user?.isBanned && <BannedUserBanner />}
      {/* ── Mobile top bar ── */}
      <div className="md:hidden fixed top-0 inset-x-0 z-30 flex items-center justify-between px-5 h-16 glass-strong border-b border-white/5">
        <span className="font-bold font-bricolage text-lg text-slate-100">FAQ Hive</span>
        <div className="flex items-center gap-4">
          <ThemeToggle />
          <button onClick={() => setIsMobileMenuOpen(true)} className="p-2 rounded-xl text-slate-300 hover:bg-white/5 transition-colors">
            <Menu size={22} />
          </button>
        </div>
      </div>

      {/* ── Mobile drawer ── */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/60 backdrop-blur-[3px] z-40 md:hidden"
            onClick={() => setIsMobileMenuOpen(false)}
          >
            <motion.div initial={{ x: '-100%' }} animate={{ x: 0 }} exit={{ x: '-100%' }}
              transition={{ type: 'spring', damping: 28, stiffness: 260 }}
              className="w-72 h-full glass-strong flex flex-col p-6 sidebar-shadow"
              onClick={e => e.stopPropagation()}
            >
              <div className="flex justify-between items-center mb-8">
                <span className="font-bold font-bricolage text-xl text-slate-100">Menu</span>
                <button onClick={() => setIsMobileMenuOpen(false)} className="p-2 rounded-xl hover:bg-white/5 transition-colors text-slate-400">
                  <X size={20} />
                </button>
              </div>
              {navSection(() => setIsMobileMenuOpen(false))}
              <div className="mt-auto pt-6 border-t border-white/5">
                <button onClick={handleLogout} className="w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-slate-400 hover:text-slate-100 hover:bg-white/5 text-sm font-semibold transition-colors font-bricolage">
                  <LogOut size={18} /> Logout
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* ── Desktop sidebar ── */}
      <aside className="hidden md:flex w-72 flex-col justify-between py-8 px-5 glass-strong sidebar-shadow z-20">
        <div>
          <div className="flex items-center justify-between mb-10 px-2">
            <div className="flex items-center gap-2.5 cursor-pointer" onClick={() => navigate('/dashboard')}>
              <div className="w-8 h-8 rounded-xl bg-white/5 border border-white/10 flex items-center justify-center">
              <Book size={16} className="text-slate-300" strokeWidth={2} />
            </div>
            <span className="font-bold font-bricolage text-lg text-slate-100">FAQ Hive</span>
            </div>
            <ThemeToggle />
          </div>
          {navSection()}
        </div>
        <div className="space-y-3">
          {user && (
            <div className="glass-card rounded-2xl p-4 flex flex-col items-center">
              <Avatar user={user} size={48} className="mb-3" showGlow={user.role === 'admin' || user.isGoldenTicket} />
              <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1 font-bricolage text-center">Reputation</p>
              <p className="text-3xl font-bold font-bricolage text-slate-100 mb-3 text-center">{user.reputation}</p>
              <div className="flex gap-1.5 text-xs font-semibold font-bricolage">
                <span className="bg-white/5 text-slate-300 px-2.5 py-1 rounded-lg border border-white/5 shadow-sm flex items-center gap-1.5"><Pizza className="w-4 h-4 text-slate-300" /> {user.pizzas}</span>
                <span className="bg-white/5 text-slate-300 px-2.5 py-1 rounded-lg border border-white/5 shadow-sm">⭐ {user.spurtiPoints}</span>
              </div>
            </div>
          )}
          <button onClick={handleLogout} className="w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-slate-400 hover:text-slate-100 hover:bg-white/5 text-sm font-semibold transition-colors font-bricolage">
            <LogOut size={18} /> Logout
          </button>
        </div>
      </aside>

      {/* ── Main content ── */}
      <div className="flex-1 overflow-y-auto scroll-smooth pt-16 md:pt-0">
        <main className="p-6 md:p-10 lg:py-12 max-w-3xl mx-auto space-y-6">

          <div>
            <h1 className="font-bold font-bricolage text-2xl md:text-3xl text-slate-100 mb-2">Contribute to FAQ</h1>
            <p className="text-slate-400 text-sm md:text-base">Help expand the community knowledge base by contributing reusable FAQs.</p>
          </div>

          <div className="relative overflow-hidden rounded-3xl glass-lavender">
            {/* Background glow */}
            <div className="absolute -top-16 -right-16 w-48 h-48 rounded-full bg-purple-500/10 blur-[100px] pointer-events-none" />
            <div className="absolute -bottom-10 -left-10 w-40 h-40 rounded-full bg-indigo-500/10 blur-[100px] pointer-events-none" />

            <div className="relative z-10 p-6 md:p-8">
              {/* Header */}
              <div className="flex items-start justify-between mb-8">
                <div>
                  <div className="flex items-center gap-2.5 mb-1.5">
                    <div className="w-8 h-8 rounded-xl bg-purple-500/10 border border-purple-400/20 flex items-center justify-center">
                      <Sparkles size={16} className="text-purple-400 animate-pulse" />
                    </div>
                    <h2 className="font-bold font-bricolage text-lg text-slate-100">Contribute a new question</h2>
                  </div>
                  <p className="text-slate-400 text-xs ml-10.5">Your submission will be AI-generalized and reviewed.</p>
                </div>
              </div>

              {/* Success State */}
              <AnimatePresence mode="wait">
                {contribResult ? (
                  <motion.div
                    key="success"
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0 }}
                    className="badge-purple rounded-2xl p-6 space-y-4"
                  >
                    <div className="flex items-center gap-2">
                      <Check size={16} className="text-purple-400" />
                      <span className="text-purple-300 text-sm font-semibold font-bricolage">AI-Generalized FAQ Generated</span>
                    </div>
                    <div className="space-y-3 font-inter">
                      <div>
                        <span className="text-[9px] font-bold tracking-widest text-slate-500 uppercase">Question</span>
                        <p className="text-slate-100 text-sm font-semibold mt-1">"{contribResult.generatedQuestion}"</p>
                      </div>
                      <div>
                        <span className="text-[9px] font-bold tracking-widest text-slate-500 uppercase">Answer</span>
                        <p className="text-slate-300 text-sm mt-1 leading-relaxed whitespace-pre-wrap">{contribResult.generatedAnswer}</p>
                      </div>
                    </div>
                    <button
                      onClick={() => setContribResult(null)}
                      className="mt-2 text-xs text-slate-400 hover:text-slate-200 transition-colors flex items-center gap-1 font-bricolage"
                    >
                      <Plus size={12} className="rotate-45" /> Contribute another
                    </button>
                  </motion.div>
                ) : (
                  <motion.form
                    key="form"
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    onSubmit={handleContribute}
                    className="space-y-5"
                  >
                    <div>
                      <label className="block text-[10px] font-bold text-slate-500 tracking-wider mb-2 uppercase font-bricolage">Category</label>
                      <CategoryDropdown
                        value={contribCategory}
                        onChange={(val) => { setContribCategory(val); if (val !== 'Other') setContribCustomCategory(''); }}
                        disabled={false}
                        categories={categories}
                      />
                    </div>

                    {contribCategory === 'Other' && (
                      <div className="animate-in fade-in duration-200">
                        <label className="block text-[10px] font-bold text-slate-500 tracking-wider mb-2 uppercase font-bricolage">Specify custom category</label>
                        <input
                          type="text"
                          required
                          value={contribCustomCategory}
                          onChange={e => setContribCustomCategory(e.target.value)}
                          placeholder="e.g. Hostels & Accommodation"
                          className="w-full bg-white/[0.02] border border-white/5 rounded-xl px-4 py-3.5 text-slate-100 placeholder-slate-600 focus:outline-none focus:border-purple-500/30 focus:ring-1 focus:ring-purple-500/30 transition-all text-sm"
                        />
                      </div>
                    )}

                    {/* Question */}
                    <div>
                      <label className="block text-[10px] font-bold text-slate-500 tracking-wider mb-2 uppercase font-bricolage">Question</label>
                      <input
                        type="text"
                        value={contribQuestion}
                        onChange={e => setContribQuestion(e.target.value)}
                        placeholder="Ask the question exactly as students might ask it..."
                        className="w-full bg-white/[0.02] border border-white/5 rounded-xl px-4 py-3.5 text-slate-100 placeholder-slate-600 focus:outline-none focus:border-purple-500/30 focus:ring-1 focus:ring-purple-500/30 transition-all text-sm"
                      />
                    </div>

                    {/* Answer */}
                    <div>
                      <label className="block text-[10px] font-bold text-slate-500 tracking-wider mb-2 uppercase font-bricolage">Answer</label>
                      <textarea
                        value={contribAnswer}
                        onChange={e => setContribAnswer(e.target.value)}
                        placeholder="Provide a clear, helpful answer..."
                        rows={4}
                        className="w-full bg-white/[0.02] border border-white/5 rounded-xl px-4 py-3.5 text-slate-100 placeholder-slate-600 focus:outline-none focus:border-purple-500/30 focus:ring-1 focus:ring-purple-500/30 transition-all text-sm resize-none"
                      />
                    </div>

                    {/* Supporting Documents */}
                    <div>
                      <label className="block text-[10px] font-bold text-slate-500 tracking-wider mb-2 uppercase font-bricolage">Supporting Documents</label>
                      <p className="text-[11px] text-slate-600 font-bricolage mb-2">Attach official notices, guidelines, offer letters, or sample forms (optional).</p>
                      <AttachmentUpload
                        attachments={contribAttachments}
                        onChange={setContribAttachments}
                      />
                    </div>

                    {/* Submit */}
                    <div className="flex items-center justify-between pt-4 border-t border-white/5">
                      <p className="text-[11px] text-slate-500 font-semibold italic hidden sm:block">AI will generalize and normalize your FAQ automatically</p>
                      <button
                        type="submit"
                        disabled={isContributing}
                        className="relative group overflow-hidden flex items-center gap-2 px-6 py-3 rounded-xl font-bold text-sm text-white transition-all disabled:opacity-60 cursor-pointer"
                        style={{
                          background: 'linear-gradient(135deg, #7c3aed, #4f46e5)',
                          boxShadow: isContributing ? 'none' : '0 0 20px rgba(124, 58, 237, 0.3)',
                        }}
                      >
                        <div className="absolute inset-0 -translate-x-full group-hover:animate-[shimmer_1.5s_infinite] bg-gradient-to-r from-transparent via-white/20 to-transparent skew-x-12" />
                        {isContributing ? (
                          <><div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> Generating...</>
                        ) : (
                          <><Sparkles size={15} /> Submit FAQ</>
                        )}
                      </button>
                    </div>
                  </motion.form>
                )}
              </AnimatePresence>
            </div>
          </div>

        </main>
      </div>
    </div>
  );
}

