                        <button onClick={() => requireLogin(() => navigate('/raise-ticket'))} className="glass-dark text-white font-semibold py-3 px-6 rounded-2xl hover:bg-white/5 border border-white/5 transition-all text-sm flex items-center gap-2 font-bricolage cursor-pointer">
                          <Plus size={16} /> Didn't find what you need? Raise a Ticket
