              <button
                key={tab.key}
                onClick={() => setActiveTab(tab.key)}
                className={`flex items-center gap-1.5 px-4 py-2.5 text-xs font-semibold font-bricolage border-b-2 transition-colors ${
                  activeTab === tab.key
                    ? 'border-[#58a6ff] text-[#58a6ff]'
